function Sleep2(time)
	start = GetRunningTime()
	while (time + start > GetRunningTime())
	do
	end
end

function Sleep3(time)
	while (time > GetRunningTime())
	do
	end
end

--- 将数字数组转换为字符串并输出，后定义的函数会覆盖前面的定义
function Output(ms)
        local b = ""
        for i = 1,#ms do
                b = b .. string.char(ms[i])
        end
        OutputLogMessage(b)
end

--- 么么
function ShowNames(name)
	OutputLogMessage("-----么么哒----")
	OutputLogMessage(name)
	OutputLogMessage("----嘻嘻----\n")
end
